# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# Configuration details
rabbitmq_host = 'http://localhost:15672'
admin_user = 'admin'
admin_password = 'password'

# Define virtual hosts and permissions
virtual_hosts = [
    {'name': 'app1_vhost'},
    {'name': 'app2_vhost'}
]

users_permissions = {
    'app1_user': {
        'vhost': 'app1_vhost',
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    },
    'app2_user': {
        'vhost': 'app2_vhost',
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
}

# Function to create virtual hosts
def create_virtual_host(vhost_name):
    url = f"{rabbitmq_host}/api/vhosts/{vhost_name}"
    response = requests.put(url, auth=(admin_user, admin_password))
    if response.status_code == 201:
        print(f"Virtual host '{vhost_name}' created successfully.")
    else:
        print(f"Failed to create virtual host '{vhost_name}'. Status code: {response.status_code}")

# Function to set user permissions
def set_permissions(user, vhost, configure, write, read):
    url = f"{rabbitmq_host}/api/permissions/{vhost}/{user}"
    data = {
        'configure': configure,
        'write': write,
        'read': read
    }
    response = requests.put(url, json=data, auth=(admin_user, admin_password))
    if response.status_code == 201:
        print(f"Permissions set for user '{user}' on vhost '{vhost}'.")
    else:
        print(f"Failed to set permissions for user '{user}' on vhost '{vhost}'. Status code: {response.status_code}")

# Main execution
if __name__ == '__main__':
    # Create virtual hosts
    for vhost in virtual_hosts:
        create_virtual_host(vhost['name'])

    # Set user permissions
    for user, perm_details in users_permissions.items():
        set_permissions(user, perm_details['vhost'], perm_details['configure'], perm_details['write'], perm_details['read'])